    36→/* ────────────────────────────────────────────────────────────────────────────
    37→ * Compile-time configuration
    38→ * ────────────────────────────────────────────────────────────────────────── */
    39→#ifndef PALETTE_SERVICE_MAX_COLORS
    40→#define PALETTE_SERVICE_MAX_COLORS 32
    41→#endif
    42→
    43→#ifndef PALETTE_SERVICE_PAGE_SIZE
    44→#define PALETTE_SERVICE_PAGE_SIZE 50
    45→#endif
    46→
    47→/* Log levels */
    48→#define LOG_TRACE  0
    49→#define LOG_DEBUG  1
    50→#define LOG_INFO   2
    51→#define LOG_WARN   3
    52→#define LOG_ERROR  4
    53→#define LOG_FATAL  5
    54→
    55→#ifndef PALETTE_LOG_LEVEL
    56→#define PALETTE_LOG_LEVEL LOG_INFO
    57→#endif
    58→
    59→/* ────────────────────────────────────────────────────────────────────────────
    60→ * Logging helpers
    61→ * ────────────────────────────────────────────────────────────────────────── */
    62→static const char *LOG_LEVEL_NAMES[] = {
    63→    "TRACE", "DEBUG", "INFO", "WARN", "ERROR", "FATAL"
    64→};
    65→
    66→static void log_internal(int level, const char *fmt, ...)
    67→{
    68→#if PALETTE_LOG_LEVEL <= LOG_FATAL
    69→    if (level < PALETTE_LOG_LEVEL) return;
    70→
    71→    va_list args;
    72→    va_start(args, fmt);
    73→
    74→#ifdef USE_SYSLOG
    75→    /* Map to syslog priorities if desired; omitted for brevity */
    76→    vfprintf(stderr, fmt, args);
    77→    fprintf(stderr, "\n");
    78→#else
    79→    struct timeval tv;
    80→    gettimeofday(&tv, NULL);
    81→    struct tm tm;
    82→    localtime_r(&tv.tv_sec, &tm);
    83→
    84→    char ts[64];
    85→    strftime(ts, sizeof(ts), "%Y-%m-%dT%H:%M:%S", &tm);
    86→
    87→    fprintf(stderr, "%s.%03ld [%s] ", ts, tv.tv_usec / 1000, LOG_LEVEL_NAMES[level]);
    88→    vfprintf(stderr, fmt, args);
    89→    fprintf(stderr, "\n");
    90→#endif
    91→
    92→    va_end(args);
    93→#endif
    94→}
