   177→/**
   178→ * palette_service_init
   179→ * Initializes internal structures; should be called once on startup.
   180→ */
   181→bool palette_service_init(void)
   182→{
   183→    if (g_ctx.initialized) {
   184→        LOGW("Palette Service already initialized");
   185→        return true;
   186→    }
   187→
   188→    if (pthread_rwlock_init(&g_ctx.lock, NULL) != 0) {
   189→        LOGE("Failed to create rwlock");
   190→        return false;
   191→    }
   192→
   193→    g_ctx.records     = NULL;
   194→    g_ctx.initialized = true;
   195→    memset(&g_ctx.metrics, 0, sizeof(g_ctx.metrics));
   196→
   197→    LOGI("Palette Service initialized");
   198→    return true;
   199→}
