   201→/**
   202→ * palette_service_shutdown
   203→ * Frees all allocated resources. Must be idempotent.
   204→ */
   205→void palette_service_shutdown(void)
   206→{
   207→    if (!g_ctx.initialized) return;
   208→
   209→    pthread_rwlock_wrlock(&g_ctx.lock);
   210→    palette_record_t *cur, *tmp;
   211→    HASH_ITER(hh, g_ctx.records, cur, tmp)
   212→    {
   213→        HASH_DEL(g_ctx.records, cur);
   214→        free(cur);
   215→    }
