   451→static bool validate_hex(const char *hex)
   452→{
   453→    if (!hex) return false;
   454→    size_t len = strlen(hex);
   455→    if (!(len == 4 || len == 7)) return false;  /* "#RGB" or "#RRGGBB" */
   456→
   457→    if (hex[0] != '#') return false;
   458→
   459→    for (size_t i = 1; i < len; ++i) {
   460→        char c = hex[i];
   461→        if (!((c >= '0' && c <= '9') ||
   462→              (c >= 'A' && c <= 'F') ||
   463→              (c >= 'a' && c <= 'f')))
   464→            return false;
   465→    }
   466→    return true;
   467→}
