   469→static bool validate_palette(const palette_record_t *p, char *err, size_t err_len)
   470→{
   471→    if (!p) { snprintf(err, err_len, "palette pointer null"); return false; }
   472→    if (strlen(p->name) == 0) {
   473→        snprintf(err, err_len, "empty name");
   474→        return false;
   475→    }
   476→    if (p->color_count == 0 || p->color_count > PALETTE_SERVICE_MAX_COLORS) {
   477→        snprintf(err, err_len, "invalid color count");
   478→        return false;
   479→    }
   480→    for (size_t i = 0; i < p->color_count; ++i) {
   481→        const palette_color_t *c = &p->colors[i];
   482→        if (strlen(c->name) == 0) {
   483→            snprintf(err, err_len, "color %zu has empty name", i);
   484→            return false;
   485→        }
   486→        if (!validate_hex(c->hex)) {
   487→            snprintf(err, err_len, "color %zu has invalid hex '%s'", i, c->hex);
   488→            return false;
   489→        }
   490→    }
   491→    return true;
   492→}
