itialized) {\n        LOGW(\"Palette Service already initialized\");\n        return true;\n    }\n\n    if (pthread_rwlock_init(&g_ctx.lock, NULL) != 0) {\n        LOGE(\"Failed to create rwlock\");\n        return false;\n    }\n\n    g_ctx.records     = NULL;\n    g_ctx.initialized = true;\n    memset(&g_ctx.metrics, 0, sizeof(g_ctx.metrics));\n\n    LOGI(\"Palette Service initialized\");\n    return true;\n}\n\n/**\n * palette_service_shutdown\n * Frees all allocated resources. Must be idempotent.\n */\nvoid palette_service_shutdown(void)\n{\n    if (!g_ctx.initialized) return;\n\n    pthread_rwlock_wrlock(&g_ctx.lock);\n    palette_record_t *cur, *tmp;\n    HASH_ITER(hh, g_ctx.records, cur, tmp)\n    {\n        HASH_DEL(g_ctx.records, cur);\n        free(cur);\n    }\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    pthread_rwlock_destroy(&g_ctx.lock);\n    g_ctx.initialized = false;\n\n    LOGI(\"Palette Service shut down\");\n}\n\n/**\n * palette_service_create_palette\n * Allocates and stores a new palette. Returns copy of stored record on success.\n */\nbool palette_service_create_palette(const char *name,\n                                    const palette_color_t *colors,\n                                    size_t color_count,\n                                    palette_record_t *out_record)\n{\n    if (!g_ctx.initialized) { LOGE(\"Service not initialized\"); return false; }\n    if (!name || !colors || color_count == 0 || color_count > PALETTE_SERVICE_MAX_COLORS) {\n        g_ctx.metrics.create_err++;\n        LOGW(\"Create request failed validation: invalid arguments\");\n        return false;\n    }\n\n    palette_record_t *rec = calloc(1, sizeof(*rec));\n    if (!rec) {\n        g_ctx.metrics.create_err++;\n        LOGE(\"Memory allocation failed\");\n        return false;\n    }\n\n    uuid_t uuid;\n    uuid_generate(uuid);\n    uuid_unparse_lower(uuid, rec->id);\n\n    strncpy(rec->name, name, sizeof(rec->name) - 1);\n    rec->color_count = color_count;\n    rec->version     = 1;\n\n    for (size_t i = 0; i < color_count; ++i)\n        memcpy(&rec->colors[i], &colors[i], sizeof(palette_color_t));\n\n    char err[256];\n    if (!validate_palette(rec, err, sizeof(err))) {\n        g_ctx.metrics.create_err++;\n        free(rec);\n        LOGW(\"Palette validation failed: %s\", err);\n        return false;\n    }\n\n    /* Store */\n    pthread_rwlock_wrlock(&g_ctx.lock);\n    HASH_ADD_STR(g_ctx.records, id, rec);\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    if (out_record) memcpy(out_record, rec, sizeof(*out_record));\n\n    g_ctx.metrics.create_ok++;\n    LOGI(\"Created palette id=%s (%zu colors)\", rec->id, rec->color_count);\n    return true;\n}\n\n/**\n * palette_service_get_palette_by_id\n * Retrieves a palette by its UUID. Returns false if not found.\n */\nbool palette_service_get_palette_by_id(const char *id, palette_record_t *out_record)\n{\n    if (!g_ctx.initialized) { LOGE(\"Service not initialized\"); return false; }\n    if (!id || !out_record) { g_ctx.metrics.read_err++; return false; }\n\n    pthread_rwlock_rdlock(&g_ctx.lock);\n    palette_record_t *rec = NULL;\n    HASH_FIND_STR(g_ctx.records, id, rec);\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    if (!rec) {\n        g_ctx.metrics.read_err++;\n        LOGD(\"Palette id=%s not found\", id);\n        return false;\n    }\n\n    memcpy(out_record, rec, sizeof(*out_record));\n    g_ctx.metrics.read_ok++;\n    return true;\n}\n\n/**\n * palette_service_list_palettes\n * Returns a paginated list of palettes. Caller must free page->items.\n */\nbool palette_service_list_palettes(palette_page_request_t req, palette_page_t *out_page)\n{\n    if (!g_ctx.initialized) { LOGE(\"Service not initialized\"); return false; }\n    if (!out_page) { g_ctx.metrics.list_err++; return false; }\n\n    if (req.page_size == 0 || req.page_size > PALETTE_SERVICE_PAGE_SIZE)\n        req.page_size = PALETTE_SERVICE_PAGE_SIZE;\n\n    /* Step 1: snapshot count */\n    pthread_rwlock_rdlock(&g_ctx.lock);\n    size_t total_items = HASH_COUNT(g_ctx.records);\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    size_t total_pages = (total_items + req.page_size - 1) / req.page_size;\n    if (req.page_number >= total_pages && total_pages > 0)\n        req.page_number = total_pages - 1;\n\n    /* Step 2: allocate array */\n    palette_record_t **arr = calloc(req.page_size, sizeof(palette_record_t *));\n    if (!arr) {\n        g_ctx.metrics.list_err++;\n        LOGE(\"Memory allocation failed (list)\");\n        return false;\n    }\n\n    /* Step 3: iterate */\n    pthread_rwlock_rdlock(&g_ctx.lock);\n    palette_record_t *rec, *tmp;\n    size_t idx = 0, skipped = 0, start = req.page_number * req.page_size;\n\n    HASH_ITER(hh, g_ctx.records, rec, tmp)\n    {\n        if (skipped < start) { skipped++; continue; }\n        if (idx >= req.page_size) break;\n        arr[idx++] = rec;\n    }\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    /* Build page */\n    out_page->items       = arr;\n    out_page->item_count  = idx;\n    out_page->total_items = total_items;\n    out_page->page_number = req.page_number;\n    out_page->total_pages = total_pages;\n\n    g_ctx.metrics.list_ok++;\n    return true;\n}\n\n/**\n * palette_service_update_palette\n * Replaces palette data atomically; increments version.\n */\nbool palette_service_update_palette(const char *id,\n                                    const char *name,\n                                    const palette_color_t *colors,\n                                    size_t color_count,\n                                    palette_record_t *out_record)\n{\n    if (!g_ctx.initialized) { LOGE(\"Service not initialized\"); return false; }\n    if (!id || !name || !colors || color_count == 0 ||\n        color_count > PALETTE_SERVICE_MAX_COLORS) {\n        g_ctx.metrics.update_err++;\n        return false;\n    }\n\n    pthread_rwlock_wrlock(&g_ctx.lock);\n    palette_record_t *rec = NULL;\n    HASH_FIND_STR(g_ctx.records, id, rec);\n    if (!rec) {\n        pthread_rwlock_unlock(&g_ctx.lock);\n        g_ctx.metrics.update_err++;\n        LOGD(\"Palette id=%s not found for update\", id);\n        return false;\n    }\n\n    strncpy(rec->name, name, sizeof(rec->name) - 1);\n    rec->color_count = color_count;\n    rec->version++;\n\n    for (size_t i = 0; i < color_count; ++i)\n        memcpy(&rec->colors[i], &colors[i], sizeof(palette_color_t));\n\n    char err[256];\n    if (!validate_palette(rec, err, sizeof(err))) {\n        pthread_rwlock_unlock(&g_ctx.lock);\n        g_ctx.metrics.update_err++;\n        LOGW(\"Palette update validation failed: %s\", err);\n        return false;\n    }\n\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    if (out_record) memcpy(out_record, rec, sizeof(*out_record));\n\n    g_ctx.metrics.update_ok++;\n    LOGI(\"Updated palette id=%s version=%u\", rec->id, rec->version);\n    return true;\n}\n\n/**\n * palette_service_delete_palette\n * Removes palette from storage.\n */\nbool palette_service_delete_palette(const char *id)\n{\n    if (!g_ctx.initialized) { LOGE(\"Service not initialized\"); return false; }\n    if (!id) { g_ctx.metrics.delete_err++; return false; }\n\n    pthread_rwlock_wrlock(&g_ctx.lock);\n    palette_record_t *rec = NULL;\n    HASH_FIND_STR(g_ctx.records, id, rec);\n    if (rec) {\n        HASH_DEL(g_ctx.records, rec);\n        free(rec);\n        pthread_rwlock_unlock(&g_ctx.lock);\n\n        g_ctx.metrics.delete_ok++;\n        LOGI(\"Deleted palette id=%s\", id);\n        return true;\n    }\n    pthread_rwlock_unlock(&g_ctx.lock);\n\n    g_ctx.metrics.delete_err++;\n    LOGD(\"Palette id=%s not found for deletion\", id);\n    return false;\n}\n\n/**\n * palette_service_dump_metrics\n * Caller provides preallocated struct. Thread-safe read.\n */\nvoid palette_service_dump_metrics(palette_metrics_t *out_metrics)\n{\n    if (!out_metrics) return;\n    pthread_rwlock_rdlock(&g_ctx.lock);\n    memcpy(out_metrics, &g_ctx.metrics, sizeof(*out_metrics));\n    pthread_rwlock_unlock(&g_ctx.lock);\n}\n\n/* ────────────────────────────────────────────────────────────────────────────\n * Validation helpers (static)\n * ────────────────────────────────────────────────────────────────────────── */\n\nstatic bool validate_hex(const char *hex)\n{\n    if (!hex) return false;\n    size_t len = strlen(hex);\n    if (!(len == 4 || len == 7)) return false;  /* \"#RGB\" or \"#RRGGBB\" */\n\n    if (hex[0] != '#') return false;\n\n    for (size_t i = 1; i < len; ++i) {\n        char c = hex[i];\n        if (!((c >= '0' && c <= '9') ||\n              (c >= 'A' && c <= 'F') ||\n              (c >= 'a' && c <= 'f')))\n            return false;\n    }\n    return true;\n}\n\nstatic bool validate_palette(const palette_record_t *p, char *err, size_t err_len)\n{\n    if (!p) { snprintf(err, err_len, \"palette pointer null\"); return false; }\n    if (strlen(p->name) == 0) {\n        snprintf(err, err_len, \"empty name\");\n        return false;\n    }\n    if (p->color_count == 0 || p->color_count > PALETTE_SERVICE_MAX_COLORS) {\n        snprintf(err, err_len, \"invalid color count\");\n        return false;\n    }\n    for (size_t i = 0; i < p->color_count; ++i) {\n        const palette_color_t *c = &p->colors[i];\n        if (strlen(c->name) == 0) {\n            snprintf(err, err_len, \"color %zu has empty name\", i);\n            return false;\n        }\n        if (!validate_hex(c->hex)) {\n            snprintf(err, err_len, \"color %zu has invalid hex '%s'\", i, c->hex);\n            return false;\n        }\n    }\n    return true;\n}\n\n/* ────────────────────────────────────────────────────────────────────────────\n * Utility\n * ────────────────────────────────────────────────────────────────────────── */\n\nstatic void free_page(palette_page_t *page)\n{\n    if (!page) return;\n    free(page->items);\n    memset(page, 0, sizeof(*page));\n}\n\n/* --------------------------------------------------------------------------\n * Example usage (unit test stub) – compile with -DPALETTE_SERVICE_TEST\n * ----------------------------------------------------------------------- */\n#ifdef PALETTE_SERVICE_TEST\nint main(void)\n{\n    if (!palette_service_init()) return EXIT_FAILURE;\n\n    palette_color_t colors[] = {\n        {\"background\", \"#112233\"},\n        {\"accent\",     \"#FFAA00\"},\n        {\"highlight\",  \"#00FF00\"}\n    };\n\n    palette_record_t created;\n    if (!palette_service_create_palette(\"Sunset\", colors, 3, &created)) {\n        LOGE(\"Create failed\");\n        return EXIT_FAILURE;\n    }\n\n    palette_record_t fetched;\n    if (palette_service_get_palette_by_id(created.id, &fetched))\n        LOGI(\"Fetched palette name=%s color_count=%zu\", fetched.name, fetched.color_count);\n\n    palette_page_request_t req = { .page_size = 10, .page_number = 0 };\n    palette_page_t page;\n    if (palette_service_list_palettes(req, &page)) {\n        LOGI(\"Listing palettes: page %zu/%zu, items=%zu\",\n             page.page_number + 1, page.total_pages, page.item_count);\n        free_page(&page);\n    }\n\n    palette_service_shutdown();\n    return EXIT_SUCCESS;\n}\n#endif /* PALETTE_SERVICE_TEST */\n", "numLines": 541, "startLine": 1, "totalLines": 541}}

1→/*
     2→ * texture_repository.c
     3→ *
     4→ * SynestheticCanvas – Texture Service
     5→ *
     6→ * This module implements the repository layer responsible for persisting and
     7→ * retrieving texture metadata and binary payloads.  It follows the Repository
     8→ * pattern so that callers are insulated from the concrete storage technology
     9→ * (PostgreSQL, in this case).
    10→ *
    11→ * NOTE:
    12→ *   The database schema expected by this repository is shown below:
    13→ *
    14→ *     CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
    15→ *
    16→ *     CREATE TABLE textures (
    17→ *         id          UUID PRIMARY KEY,
    18→ *         name        VARCHAR(255) NOT NULL,
    19→ *         palette_id  UUID         NOT NULL,
    20→ *         data        BYTEA        NOT NULL,
    21→ *         created_at  TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    22→ *         updated_at  TIMESTAMPTZ  NOT NULL DEFAULT NOW()
    23→ *     );
    24→ *
    25→ * Compile flags (example):
    26→ *   cc -Wall -Wextra -pthread -lpq -o texture_repository texture_repository.c
    27→ */
    28→
    29→#include <stdio.h>
    30→#include <stdlib.h>
    31→#include <stdint.h>
    32→#include <string.h>
    33→#include <time.h>
    34→#include <pthread.h>
    35→#include <syslog.h>
    36→#include <libpq-fe.h>
    37→
    38→#include "texture_repository.h"   /* Header for this source file */
    39→
    40→/* ---------------------------------------------------------------------------*/
    41→/* Constants                                                                  */
    42→/* ---------------------------------------------------------------------------*/
    43→
    44→#define REPO_OK             0
    45→#define REPO_ERR_MEM       -1
    46→#define REPO_ERR_DB        -2
    47→#define REPO_ERR_NOT_FOUND -3
    48→
    49→/* ISO-8601 conversion buffers */
    50→#define TIMESTAMP_BUFSZ    32
    51→
    52→/* Prepared statement names  */
    53→static const char *STMT_CREATE = "texture_create";
    54→static const char *STMT_GET    = "texture_get";
    55→static const char *STMT_UPDATE = "texture_update";
    56→static const char *STMT_DELETE = "texture_delete";
    57→static const char *STMT_LIST   = "texture_list";
    58→
    59→/* ---------------------------------------------------------------------------*/
    60→/* Internal helpers                                                           */
    61→/* ---------------------------------------------------------------------------*/
    62→
    63→/* Guard all repository operations with this macro */
    64→#define WITH_LOCK(repo) \
    65→    for (bool _once = true; _once; _once = false) \
    66→        for (pthread_mutex_lock(&(repo)->lock); _once; pthread_mutex_unlock(&(repo)->lock), _once = false)
    67→
    68→/* Convert time_t → ISO-8601 UTC string (yyyy-mm-ddThh:mm:ssZ) */
    69→static void
    70→time_to_iso_utc(time_t t, char *buf, size_t bufsz)
    71→{
    72→    struct tm tm_utc;
    73→    gmtime_r(&t, &tm_utc);
    74→    strftime(buf, bufsz, "%Y-%m-%dT%H:%M:%SZ", &tm_utc);
    75→}
    76→
    77→/* Parse ISO-8601 UTC timestamp → time_t; returns 0 on failure */
    78→static time_t
    79→iso_utc_to_time(const char *s)
    80→{
    81→    struct tm tm_utc = {0};
    82→    if (!strptime(s, "%Y-%m-%d %H:%M:%S", &tm_utc))
    83→        return (time_t)0;
    84→
    85→    /* pg timestamp without timezone delivered in session TZ; assume UTC */
    86→    return timegm(&tm_utc);
    87→}
    88→
    89→/* Free heap-allocated members of a texture object */
    90→static void
    91→texture_clear(texture_t *tx)
    92→{
    93→    if (!tx) return;
    94→    free(tx->data);
    95→    memset(tx, 0, sizeof(*tx));
    96→}
    97→
    98→/* ---------------------------------------------------------------------------*/
    99→/* Public API                                                                 */
   100→/* ---------------------------------------------------------------------------*/
   101→
   102→texture_repository_t *
   103→texture_repository_new(const char *conninfo)
   104→{
   105→    if (!conninfo) {
   106→        syslog(LOG_ERR, "texture_repository_new: conninfo is NULL");
   107→        return NULL;
   108→    }
   109→
   110→    texture_repository_t *repo = calloc(1, sizeof(*repo));
   111→    if (!repo) {
   112→        syslog(LOG_CRIT, "texture_repository_new: out of memory");
   113→        return NULL;
   114→    }
   115→
   116→    pthread_mutex_init(&repo->lock, NULL);
   117→
   118→    repo->conn = PQconnectdb(conninfo);
   119→    if (PQstatus(repo->conn) != CONNECTION_OK) {
   120→        syslog(LOG_CRIT, "PostgreSQL connection failed: %s",
   121→               PQerrorMessage(repo->conn));
   122→        PQfinish(repo->conn);
   123→        free(repo);
   124→        return NULL;
   125→    }
   126→
   127→    /* Prepare statements upfront; exit if any preparation fails */
   128→    struct {
   129→        const char *name;
   130→        const char *sql;
   131→        int         nParams;
   132→    } stmts[] = {
   133→        { STMT_CREATE,
   134→          "INSERT INTO textures "
   135→          "(id, name, palette_id, data, created_at, updated_at) "
   136→          "VALUES ($1, $2, $3, $4, $5, $6)",
   137→          6 },
   138→        { STMT_GET,
   139→          "SELECT id, name, palette_id, data, "
   140→          "       created_at, updated_at "
   141→          "FROM textures WHERE id = $1",
   142→          1 },
   143→        { STMT_UPDATE,
   144→          "UPDATE textures SET "
   145→          "  name = $2, "
   146→          "  palette_id = $3, "
   147→          "  data = $4, "
   148→          "  updated_at = $5 "
   149→          "WHERE id = $1",
   150→          5 },
   151→        { STMT_DELETE,
   152→          "DELETE FROM textures WHERE id = $1",
   153→          1 },
   154→        { STMT_LIST,
   155→          "SELECT id, name, palette_id, data, "
   156→          "       created_at, updated_at "
   157→          "FROM textures "
   158→          "ORDER BY created_at DESC "
   159→          "LIMIT $1 OFFSET $2",
   160→          2 },
   161→    };
   162→
   163→    for (size_t i = 0; i < sizeof(stmts) / sizeof(stmts[0]); ++i) {
   164→        PGresult *res = PQprepare(repo->conn,
   165→                                  stmts[i].name,
   166→                                  stmts[i].sql,
   167→                                  stmts[i].nParams,
   168→                                  NULL);
   169→        if (PQresultStatus(res) != PGRES_COMMAND_OK) {
   170→            syslog(LOG_CRIT, "Failed to prepare statement '%s': %s",
   171→                   stmts[i].name, PQerrorMessage(repo->conn));
   172→            PQclear(res);
   173→            texture_repository_destroy(repo);
   174→            return NULL;
   175→        }
   176→        PQclear(res);
   177→    }
   178→
   179→    syslog(LOG_INFO, "Texture repository initialized");
   180→    return repo;
   181→}
   182→
   183→void
   184→texture_repository_destroy(texture_repository_t *repo)
   185→{
   186→    if (!repo) return;
   187→
   188→    WITH_LOCK(repo) {
   189→        PQfinish(repo->conn);
   190→    }
   191→    pthread_mutex_destroy(&repo->lock);
   192→    free(repo);
   193→
   194→    syslog(LOG_INFO, "Texture repository destroyed");
   195→}
   196→
   197→int
   198→texture_repository_create(texture_repository_t *repo,
   199→                          const texture_t *texture)
   200→{
   201→    if (!repo || !texture) return REPO_ERR_DB;
   202→
   203→    char created_at[TIMESTAMP_BUFSZ];
   204→    char updated_at[TIMESTAMP_BUFSZ];
   205→
   206→    time_to_iso_utc(texture->created_at, created_at, sizeof(created_at));
   207→    time_to_iso_utc(texture->updated_at, updated_at, sizeof(updated_at));
   208→
   209→    const char *params[6];
   210→    int         lengths[6];
   211→    int         formats[6] = {0};
   212→
   213→    params[0] = texture->id;
   214→    lengths[0] = 0;
   215→
   216→    params[1] = texture->name;
   217→    lengths[1] = 0;
   218→
   219→    params[2] = texture->palette_id;
   220→    lengths[2] = 0;
   221→
   222→    params[3]   = (const char *)texture->data;
   223→    lengths[3]  = (int)texture->data_size;
   224→    formats[3]  = 1; /* binary */
   225→
   226→    params[4]  = created_at;
   227→    params[5]  = updated_at;
   228→    lengths[4] = lengths[5] = 0;
   229→
   230→    PGresult *res = NULL;
   231→    WITH_LOCK(repo) {
   232→        res = PQexecPrepared(repo->conn,
   233→                             STMT_CREATE,
   234→                             6,
   235→                             params,
   236→                             lengths,
   237→                             formats,
   238→                             0);
   239→    }
   240→
   241→    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
   242→        syslog(LOG_ERR, "texture_repository_create: %s",
   243→               PQerrorMessage(repo->conn));
   244→        PQclear(res);
   245→        return REPO_ERR_DB;
   246→    }
   247→
   248→    PQclear(res);
   249→    return REPO_OK;
   250→}
   251→
   252→int
   253→texture_repository_get(texture_repository_t *repo,
   254→                       const char *id,
   255→                       texture_t *out_texture)
   256→{
   257→    if (!repo || !id || !out_texture) return REPO_ERR_DB;
   258→
   259→    const char *params[1] = { id };
   260→    int lengths[1]  = { 0 };
   261→    int formats[1]  = { 0 };
   262→
   263→    PGresult *res = NULL;
   264→    WITH_LOCK(repo) {
   265→        res = PQexecPrepared(repo->conn,
   266→                             STMT_GET,
   267→                             1,
   268→                             params,
   269→                             lengths,
   270→                             formats,
   271→                             0);
   272→    }
   273→
   274→    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
   275→        syslog(LOG_ERR, "texture_repository_get: %s",
   276→               PQerrorMessage(repo->conn));
   277→        PQclear(res);
   278→        return REPO_ERR_DB;
   279→    }
   280→
   281→    if (PQntuples(res) == 0) {
   282→        PQclear(res);
   283→        return REPO_ERR_NOT_FOUND;
   284→    }
   285→
   286→    /* Fetch data */
   287→    int idx = 0;
   288→    strncpy(out_texture->id, PQgetvalue(res, 0, idx++), sizeof(out_texture->id)-1);
   289→    strncpy(out_texture->name, PQgetvalue(res, 0, idx++), sizeof(out_texture->name)-1);
   290→    strncpy(out_texture->palette_id, PQgetvalue(res, 0, idx++), sizeof(out_texture->palette_id)-1);
   291→
   292→    /* BYTEA field */
   293→    size_t bin_len = (size_t)PQgetlength(res, 0, idx);
   294→    const unsigned char *bin_data = (const unsigned char *)PQgetvalue(res, 0, idx++);
   295→    out_texture->data = malloc(bin_len);
   296→    if (!out_texture->data) {
   297→        PQclear(res);
   298→        return REPO_ERR_MEM;
   299→    }
   300→    memcpy(out_texture->data, bin_data, bin_len);
   301→    out_texture->data_size = bin_len;
   302→
   303→    /* created_at / updated_at */
   304→    out_texture->created_at = iso_utc_to_time(PQgetvalue(res, 0, idx++));
   305→    out_texture->updated_at = iso_utc_to_time(PQgetvalue(res, 0, idx++));
   306→
   307→    PQclear(res);
   308→    return REPO_OK;
   309→}
   310→
   311→int
   312→texture_repository_update(texture_repository_t *repo,
   313→                          const texture_t *texture)
   314→{
   315→    if (!repo || !texture) return REPO_ERR_DB;
   316→
   317→    char updated_at[TIMESTAMP_BUFSZ];
   318→    time_to_iso_utc(texture->updated_at, updated_at, sizeof(updated_at));
   319→
   320→    const char *params[5];
   321→    int         lengths[5];
   322→    int         formats[5] = {0};
   323→
   324→    params[0] = texture->id;
