   155→/* Basic gradient noise (returns value in [0;1]) */
   156→static void
   157→generate_noise_texture(uint32_t width, uint32_t height,
   158→                       float frequency, uint8_t *out_pixels)
   159→{
   160→    for (uint32_t y = 0; y < height; ++y) {
   161→        for (uint32_t x = 0; x < width; ++x) {
   162→            float nx = x * frequency;
   163→            float ny = y * frequency;
   164→            /* pseudo-random value per pixel */
   165→            float v = fabsf(sinf(nx * 12.9898f + ny * 78.233f) * 43758.5453f);
   166→            v = v - floorf(v); /* fract */
   167→
   168→            uint8_t c = (uint8_t)(v * 255.0f);
   169→            size_t idx = ((size_t)y * width + x) * 4;
   170→            out_pixels[idx + 0] = c;  /* R */
   171→            out_pixels[idx + 1] = c;  /* G */
   172→            out_pixels[idx + 2] = c;  /* B */
   173→            out_pixels[idx + 3] = 255;/* A opaque */
   174→        }
   175→    }
   176→}
