   178→/* ------------------------------------------------------------------------
   179→ * LRU Cache
   180→ * ----------------------------------------------------------------------*/
   181→typedef struct texture_cache {
   182→    pthread_mutex_t lock;
   183→    cache_entry_t  *head; /* MRU */
   184→    cache_entry_t  *tail; /* LRU */
   185→    size_t          items;
   186→    size_t          bytes;
   187→} texture_cache_t;
   188→
   189→static texture_cache_t g_cache = {
   190→    .lock  = PTHREAD_MUTEX_INITIALIZER,
   191→    .head  = NULL,
   192→    .tail  = NULL,
   193→    .items = 0,
   194→    .bytes = 0
   195→};
   196→
   197→static void
   198→cache_move_to_front(cache_entry_t *entry)
   199→{
   200→    if (g_cache.head == entry)
   201→        return;
   202→
   203→    /* detach */
   204→    if (entry->prev)
   205→        entry->prev->next = entry->next;
   206→    if (entry->next)
   207→        entry->next->prev = entry->prev;
   208→    if (g_cache.tail == entry)
   209→        g_cache.tail = entry->prev;
   210→
   211→    /* insert at front */
   212→    entry->prev = NULL;
   213→    entry->next = g_cache.head;
   214→    if (g_cache.head)
   215→        g_cache.head->prev = entry;
   216→    g_cache.head = entry;
   217→    if (!g_cache.tail)
   218→        g_cache.tail = entry;
   219→}
   220→
   221→static cache_entry_t *
   222→cache_find(const char *id)
   223→{
   224→    cache_entry_t *it = g_cache.head;
   225→    while (it) {
   226→        if (strcmp(it->meta.id, id) == 0)
   227→            return it;
   228→        it = it->next;
   229→    }
   230→    return NULL;
   231→}
   232→
   233→static void
   234→cache_evict_if_needed(void)
   235→{
   236→    while (g_cache.items > MAX_CACHE_ITEMS) {
   237→        cache_entry_t *victim = g_cache.tail;
   238→        if (!victim)
   239→            return;
   240→        /* detach */
   241→        if (victim->prev)
   242→            victim->prev->next = NULL;
   243→        g_cache.tail = victim->prev;
   244→        if (g_cache.head == victim)
   245→            g_cache.head = NULL;
   246→
   247→        g_cache.items--;
   248→        g_cache.bytes -= victim->size;
   249→        LOG_INFO("Evicted texture %s from cache (now %" PRIu64 " KiB)",
   250→                 victim->meta.id, (uint64_t)(g_cache.bytes / 1024));
   251→
   252→        free(victim->pixels);
   253→        free(victim);
   254→    }
   255→}
   256→
   257→static void
   258→cache_insert(cache_entry_t *entry)
   259→{
   260→    entry->prev = NULL;
   261→    entry->next = g_cache.head;
   262→    if (g_cache.head)
   263→        g_cache.head->prev = entry;
   264→    g_cache.head = entry;
   265→    if (!g_cache.tail)
   266→        g_cache.tail = entry;
   267→
   268→    g_cache.items++;
   269→    g_cache.bytes += entry->size;
   270→    cache_evict_if_needed();
   271→}
