   317→ * ----------------------------------------------------------------------*/
   318→static int
   319→handle_post_textures(rest_ctx_t *ctx)
   320→{
   321→    uint32_t width  = 0, height = 0;
   322→    float freq = DEFAULT_NOISE_FREQ;
   323→
   324→    const char *width_str  = MHD_lookup_connection_value(ctx->conn, MHD_POST_FIELD_KIND, "width");
   325→    const char *height_str = MHD_lookup_connection_value(ctx->conn, MHD_POST_FIELD_KIND, "height");
   326→    const char *freq_str   = MHD_lookup_connection_value(ctx->conn, MHD_POST_FIELD_KIND, "freq");
   327→
   328→    if (width_str)  width  = (uint32_t)strtoul(width_str, NULL, 10);
   329→    if (height_str) height = (uint32_t)strtoul(height_str, NULL, 10);
   330→    if (freq_str)   freq   = strtof(freq_str, NULL);
   331→
   332→    if (width == 0 || height == 0 || width > MAX_TEXTURE_SIDE || height > MAX_TEXTURE_SIDE) {
   333→        return resp_plain(ctx->conn, MHD_HTTP_BAD_REQUEST, "Invalid dimensions");
   334→    }
   335→
   336→    size_t bytes = (size_t)width * height * 4;
   337→    uint8_t *pixels = malloc(bytes);
   338→    if (!pixels)
   339→        return resp_plain(ctx->conn, MHD_HTTP_INTERNAL_SERVER_ERROR, "OOM");
   340→
   341→    generate_noise_texture(width, height, freq, pixels);
   342→
   343→    texture_meta_t meta = {0};
   344→    uuid_t uu;
   345→    uuid_generate(uu);
   346→    uuid_unparse_lower(uu, meta.id);
   347→    meta.width  = width;
   348→    meta.height = height;
   349→    meta.created_at = time(NULL);
   350→    snprintf(meta.file_path, sizeof meta.file_path,
   351→             STORAGE_DIR "/%s.raw", meta.id);
   352→
   353→    pthread_mutex_lock(&g_repo.lock);
   354→    bool ok = repo_save_raw(&meta, pixels);
   355→    pthread_mutex_unlock(&g_repo.lock);
   356→    if (!ok) {
   357→        free(pixels);
   358→        return resp_plain(ctx->conn, MHD_HTTP_INTERNAL_SERVER_ERROR, "Save failed");
   359→    }
   360→
   361→    /* Add to cache */
   362→    pthread_mutex_lock(&g_cache.lock);
   363→    cache_entry_t *item = malloc(sizeof *item);
   364→    if (!item) {
   365→        pthread_mutex_unlock(&g_cache.lock);
   366→        free(pixels);
   367→        return resp_plain(ctx->conn, MHD_HTTP_INTERNAL_SERVER_ERROR, "OOM");
   368→    }
   369→    item->meta  = meta;
   370→    item->pixels = pixels;
   371→    item->size   = bytes;
   372→    cache_insert(item);
   373→    pthread_mutex_unlock(&g_cache.lock);
   374→
   375→    char json[256];
   376→    snprintf(json, sizeof json,
   377→             "{\"id\":\"%s\",\"width\":%u,\"height\":%u}",
   378→             meta.id, meta.width, meta.height);
