   384→/* ------------------------------------------------------------------------
   385→ * Endpoint: GET /textures/<uuid>/metadata
   386→ * ----------------------------------------------------------------------*/
   387→static int
   388→handle_get_texture_metadata(rest_ctx_t *ctx, const char *uuid_str)
   389→{
   390→    pthread_mutex_lock(&g_cache.lock);
   391→    cache_entry_t *hit = cache_find(uuid_str);
   392→    if (hit)
   393→        cache_move_to_front(hit);
   394→    pthread_mutex_unlock(&g_cache.lock);
   395→
   396→    texture_meta_t meta;
   397→    bool found = false;
   398→
   399→    if (hit) {
   400→        meta   = hit->meta;
   401→        found = true;
   402→    } else {
   403→        /* Fall back to disk */
   404→        char file_path[PATH_MAX];
   405→        snprintf(file_path, sizeof file_path, STORAGE_DIR "/%s.raw", uuid_str);
   406→        struct stat st;
   407→        if (stat(file_path, &st) == 0) {
   408→            /* Dimensions are not stored on disk header. In real code you would 
   409→             * store metadata in DB; we'll derive from file size here. */
   410→            size_t bytes = (size_t)st.st_size;
   411→            uint32_t side = (uint32_t)sqrt((double)(bytes / 4));
   412→            if (side * side * 4 == bytes) {
   413→                strncpy(meta.id, uuid_str, sizeof meta.id);
   414→                meta.width  = side;
   415→                meta.height = side;
   416→                strncpy(meta.file_path, file_path, sizeof meta.file_path);
   417→                meta.created_at = st.st_mtime;
   418→                found = true;
   419→            }
   420→        }
   421→    }
   422→
   423→    if (!found)
   424→        return resp_plain(ctx->conn, MHD_HTTP_NOT_FOUND, "Not found");
   425→
   426→    char created[32];
   427→    struct tm tm;
   428→    gmtime_r(&meta.created_at, &tm);
   429→    strftime(created, sizeof created, "%FT%TZ", &tm);
   430→
   431→    char json[256];
   432→    snprintf(json, sizeof json,
   433→             "{\"id\":\"%s\",\"width\":%u,\"height\":%u,\"created\":\"%s\"}",
   434→             meta.id, meta.width, meta.height, created);
   435→
   436→    return resp_json(ctx->conn, MHD_HTTP_OK, json);
   437→}
