   514→         const char *url,
   515→         const char *method,
   516→         const char *version,
   517→         const char *upload_data,
   518→         size_t      *upload_data_size,
   519→         void       **con_cls)
   520→{
   521→    (void)cls; (void)version; (void)upload_data; (void)upload_data_size;
   522→
   523→    rest_ctx_t ctx = {.conn = conn, .url = url, .method = method};
   524→
   525→    /* Routing */
   526→    if (strcmp(method, MHD_HTTP_METHOD_POST) == 0 &&
   527→        strcmp(url, "/textures") == 0) {
   528→        return handle_post_textures(&ctx);
   529→    }
   530→
   531→    if (strncmp(url, "/textures/", 10) == 0) {
   532→        const char *uuid_part = url + 10;
   533→        const char *slash = strchr(uuid_part, '/');
   534→        if (!slash)
   535→            return resp_plain(conn, MHD_HTTP_NOT_FOUND, "Bad URL");
   536→
   537→        char uuid[37] = {0};
   538→        size_t len = slash - uuid_part;
   539→        if (len >= sizeof uuid)
   540→            return resp_plain(conn, MHD_HTTP_BAD_REQUEST, "UUID toolong");
   541→        memcpy(uuid, uuid_part, len);
