   543→        if (strcmp(slash, "/metadata") == 0 &&
   544→            strcmp(method, MHD_HTTP_METHOD_GET) == 0) {
   545→            return handle_get_texture_metadata(&ctx, uuid);
   546→        }
   547→        if (strcmp(slash, "/raw") == 0 &&
   548→            strcmp(method, MHD_HTTP_METHOD_GET) == 0) {
   549→            return handle_get_texture_raw(&ctx, uuid);
   550→        }
   551→    }
   552→
   553→    return resp_plain(conn, MHD_HTTP_NOT_FOUND, "Not found");
