    46→/* Simple timestamped log macros */
    47→#define LOG_FMT(ts, lvl, fmt) "[%s] [%s] " fmt "\n", ts, lvl
    48→#define LOG_INF(fmt, ...) log_write("INFO",  fmt, ##__VA_ARGS__)
    49→#define LOG_WRN(fmt, ...) log_write("WARN",  fmt, ##__VA_ARGS__)
