     2→ *  fallback_handlers.c
     3→ *
     4→ *  SynestheticCanvas – API Gateway
     5→ *  ------------------------------------------------------------
     6→ *  REST fallback handlers used when:
     7→ *      1. A legacy REST endpoint is requested.
     8→ *      2. A GraphQL resolver or downstream micro-service is
     9→ *         temporarily unavailable.
    10→ *      3. An unsupported HTTP method or resource is addressed.
    11→ *
    12→ *  The gateway tries to keep the public contract stable, even if
    13→ *  individual services are rebooted or upgraded.  The handlers in
    14→ *  this compilation unit wrap transient errors in a deterministic,
    15→ *  well-structured JSON envelope so that consumer applications
    16→ *  (e.g., WebGL visualisations, Max/MSP patches, Unity shaders)
    17→ *  can degrade gracefully instead of crashing.
    18→ *
    19→ *  ------------------------------------------------------------------
    20→ *  Author  : SynestheticCanvas Core Team
    21→ *  License : MIT
    22→ */
    23→
    24→#include "fallback_handlers.h"
    25→
    26→#include <errno.h>
    27→#include <pthread.h>
    28→#include <stdio.h>
    29→#include <stdlib.h>
    30→#include <string.h>
    31→#include <time.h>
    32→
    33→#include "cjson/cJSON.h"          /* Third-party lightweight JSON library */
    34→#include "core/logger.h"          /* Project-wide structured logger        */
    35→#include "core/mime_types.h"      /* Utility for Content-Type resolution   */
    36→#include "core/version.h"         /* Semantic version of the gateway       */
    37→
    38→/* ------------------------------------------------------------------ */
    39→/* Static helpers                                                     */
    40→/* ------------------------------------------------------------------ */
    41→
    42→/* ISO-8601 timestamp generator (UTC, to the second) */
    43→static void
    44→iso8601_now(char buffer[static 32])
    45→{
    46→    time_t     t  = time(NULL);
    47→    struct tm  tm;
    48→    gmtime_r(&t, &tm);
    49→    strftime(buffer, 32, "%Y-%m-%dT%H:%M:%SZ", &tm);
    50→}
    51→
    52→/* Build a standardised error JSON envelope:
    53→ * {
    54→ *   "error": {
    55→ *       "code"     : 404,
    56→ *       "type"     : "NOT_FOUND",
    57→ *       "message"  : "Resource '/v1/foobar' does not exist.",
    58→ *       "timestamp": "2023-11-18T14:27:08Z",
    59→ *       "gateway"  : "v3.2.0"
    60→ *   }
    61→ * }
    62→ */
    63→static char *
    64→build_error_payload(int             code,
    65→                    const char     *type,
    66→                    const char     *message_fmt,
    67→                    ...)
    68→{
    69→    char                iso[32];
    70→    iso8601_now(iso);
    71→
    72→    /* Compose `message` (variadic) */
    73→    va_list ap;
    74→    va_start(ap, message_fmt);
    75→    char message[256];
    76→    vsnprintf(message, sizeof(message), message_fmt, ap);
    77→    va_end(ap);
    78→
    79→    cJSON *root  = cJSON_CreateObject();
    80→    cJSON *error = cJSON_AddObjectToObject(root, "error");
    81→
    82→    cJSON_AddNumberToObject(error, "code", code);
    83→    cJSON_AddStringToObject(error, "type", type);
    84→    cJSON_AddStringToObject(error, "message", message);
    85→    cJSON_AddStringToObject(error, "timestamp", iso);
    86→    cJSON_AddStringToObject(error, "gateway", SC_GATEWAY_VERSION);
    87→
    88→    char *json = cJSON_PrintUnformatted(root);
    89→    cJSON_Delete(root);
    90→    return json; /* caller must free() */
    91→}
    92→
    93→/* ------------------------------------------------------------------ */
    94→/* Introspection cache: used when the GraphQL engine is offline       */
    95→/* ------------------------------------------------------------------ */
    96→
    97→#define INTROSPECTION_CACHE_TTL  30 /* seconds */
    98→
    99→typedef struct
   100→{
   101→    char   *body;
   102→    size_t  len;
   103→    time_t  stored_at;
   104→} CachedIntrospection;
   105→
   106→static pthread_rwlock_t    g_introspect_lock = PTHREAD_RWLOCK_INITIALIZER;
   107→static CachedIntrospection g_introspect      = { .body = NULL, .len = 0, .stored_at = 0 };
   108→
   109→static const char *
   110→read_fallback_introspection(size_t *out_len)
   111→{
   112→    /* Quick path: Is the current cache still fresh? */
   113→    time_t now = time(NULL);
   114→
   115→    pthread_rwlock_rdlock(&g_introspect_lock);
   116→    if (g_introspect.body && (now - g_introspect.stored_at) < INTROSPECTION_CACHE_TTL)
   117→    {
   118→        *out_len = g_introspect.len;
   119→        const char *ret = g_introspect.body;
   120→        pthread_rwlock_unlock(&g_introspect_lock);
   121→        return ret;
   122→    }
   123→    pthread_rwlock_unlock(&g_introspect_lock);
   124→
   125→    /* Slow path: (Re)load from disk */
   126→    FILE *fp = fopen("/var/lib/synesthetic/introspection_fallback.json", "rb");
   127→    if (!fp)
   128→    {
   129→        LOG_WARN("Failed to open cached introspection file: %s", strerror(errno));
   130→        return NULL;
   131→    }
   132→
   133→    if (fseek(fp, 0, SEEK_END) != 0)
   134→    {
   135→        fclose(fp);
   136→        return NULL;
   137→    }
   138→
   139→    long len = ftell(fp);
   140→    if (len <= 0 || fseek(fp, 0, SEEK_SET) != 0)
   141→    {
   142→        fclose(fp);
   143→        return NULL;
   144→    }
   145→
   146→    char *buf = calloc((size_t)len + 1, 1);
   147→    if (fread(buf, 1, (size_t)len, fp) != (size_t)len)
   148→    {
   149→        LOG_WARN("Incomplete read of introspection fallback.");
   150→        fclose(fp);
   151→        free(buf);
   152→        return NULL;
   153→    }
   154→    fclose(fp);
   155→
   156→    pthread_rwlock_wrlock(&g_introspect_lock);
   157→
   158→    /* Clear existing cache */
   159→    free(g_introspect.body);
   160→    g_introspect.body      = buf;
   161→    g_introspect.len       = (size_t)len;
   162→    g_introspect.stored_at = now;
   163→
   164→    *out_len = g_introspect.len;
   165→
   166→    pthread_rwlock_unlock(&g_introspect_lock);
   167→    return buf;
   168→}
