   170→/* ------------------------------------------------------------------ */
   171→/* Public handler implementations                                     */
   172→/* ------------------------------------------------------------------ */
   173→
   174→RestResponse
   175→rest_fallback_not_found(const RestRequest *req)
   176→{
   177→    LOG_DEBUG("[REST] Not-Found handler for URI '%s'", req->uri);
   178→
   179→    char *payload = build_error_payload(
   180→        404,
   181→        "NOT_FOUND",
   182→        "Resource '%s' does not exist.", req->uri);
   183→
   184→    RestResponse res = {
   185→        .status_code  = 404,
   186→        .content_type = MIME_APP_JSON,
   187→        .body         = payload,
   188→        .body_len     = strlen(payload),
   189→        .must_free    = true
   190→    };
   191→    return res;
   192→}
   193→
   194→RestResponse
   195→rest_fallback_method_not_allowed(const RestRequest *req,
   196→                                 HttpMethod         allowed)
   197→{
   198→    LOG_DEBUG("[REST] Method-Not-Allowed handler for URI '%s'", req->uri);
   199→
   200→    const char *method_name = http_method_to_str(req->method);
   201→    const char *allowed_str = http_method_to_str(allowed);
   202→
   203→    char *payload = build_error_payload(
   204→        405,
   205→        "METHOD_NOT_ALLOWED",
   206→        "Method %s is not allowed on '%s'. Allowed: %s.",
   207→        method_name,
   208→        req->uri,
   209→        allowed_str);
   210→
   211→    RestResponse res = {
   212→        .status_code  = 405,
   213→        .content_type = MIME_APP_JSON,
   214→        .body         = payload,
   215→        .body_len     = strlen(payload),
   216→        .must_free    = true
   217→    };
   218→
   219→    /* Add mandatory 'Allow' header (RFC 7231 §6.5.5) */
   220→    res.headers_len = snprintf(res.headers, sizeof res.headers,
   221→                               "Allow: %s\r\n", allowed_str);
   222→
   223→    return res;
   224→}
   225→
   226→RestResponse
   227→rest_fallback_service_unavailable(const RestRequest *req,
   228→                                  const char        *service_name,
   229→                                  unsigned           retry_after_sec)
   230→{
   231→    LOG_WARN("[REST] Service '%s' unavailable ‑ Fallback triggered for URI '%s'",
   232→             service_name, req->uri);
   233→
   234→    char *payload = build_error_payload(
   235→        503,
   236→        "SERVICE_UNAVAILABLE",
   237→        "The %s service is temporarily unavailable. Please retry later.",
   238→        service_name);
   239→
   240→    RestResponse res = {
   241→        .status_code  = 503,
   242→        .content_type = MIME_APP_JSON,
   243→        .body         = payload,
   244→        .body_len     = strlen(payload),
   245→        .must_free    = true
   246→    };
   247→
   248→    if (retry_after_sec > 0)
   249→    {
   250→        res.headers_len = snprintf(res.headers, sizeof res.headers,
   251→                                   "Retry-After: %u\r\n", retry_after_sec);
   252→    }
   253→
   254→    return res;
   255→}
   256→
   257→/* Legacy palette endpoint redirect/fallback
   258→ * Historically, users called:
   259→ *      GET /v1/palette/<palette-id>
   260→ * The new canonical route is:
   261→ *      GET /v3/palette?id=<palette-id>
   262→ *
   263→ * We keep the old endpoint alive but mark it as deprecated.
   264→ */
   265→RestResponse
   266→rest_fallback_legacy_palette(const RestRequest *req,
   267→                             const char        *palette_id)
   268→{
   269→    (void)req; /* Not used beyond log. */
   270→    LOG_INFO("[REST] Legacy palette endpoint accessed: id='%s'", palette_id);
   271→
   272→    /* Build JSON informing of deprecation */
   273→    cJSON *root  = cJSON_CreateObject();
   274→    cJSON *meta  = cJSON_AddObjectToObject(root, "meta");
   275→    cJSON *data  = cJSON_AddObjectToObject(root, "data");
   276→
   277→    cJSON_AddStringToObject(meta, "status",  "DEPRECATED");
   278→    cJSON_AddStringToObject(meta, "target",  "/v3/palette");
   279→    cJSON_AddStringToObject(meta, "message", "This endpoint will be removed in v4.0.0");
   280→
   281→    cJSON_AddStringToObject(data, "paletteId", palette_id);
   282→    cJSON_AddStringToObject(data, "redirect", "/v3/palette?id=<paletteId>");
   283→
   284→    char *json = cJSON_PrintUnformatted(root);
   285→    cJSON_Delete(root);
   286→
   287→    RestResponse res = {
   288→        .status_code  = 200,
   289→        .content_type = MIME_APP_JSON,
   290→        .body         = json,
   291→        .body_len     = strlen(json),
   292→        .must_free    = true
   293→    };
   294→    return res;
   295→}
   296→
   297→/* Return an introspection JSON snapshot when the GraphQL engine
   298→ * (powered by libgraphqlparser & LLVM JIT) is unreachable.
   299→ */
   300→RestResponse
   301→rest_fallback_graphql_introspection(const RestRequest *req)
   302→{
   303→    (void)req;
   304→    size_t len   = 0;
   305→    const char *body = read_fallback_introspection(&len);
   306→
   307→    if (!body)
   308→    {
   309→        /* Last-ditch effort: give a 503 instead of crashing */
   310→        return rest_fallback_service_unavailable(
   311→            req, "GraphQL", /* retry_after = */ 5);
   312→    }
   313→
   314→    RestResponse res = {
   315→        .status_code  = 200,
   316→        .content_type = MIME_APP_JSON,
   317→        .body         = (char *)body, /* NOTE: cached pointer, do NOT free. */
   318→        .body_len     = len,
   319→        .must_free    = false
   320→    };
   321→    return res;
   322→}
   323→
   324→/* ------------------------------------------------------------------ */
   325→/* Destructor to clean up cache at program termination                */
   326→/* ------------------------------------------------------------------ */
   327→
   328→__attribute__((destructor))
   329→static void
   330→cleanup_introspection_cache(void)
   331→{
   332→    pthread_rwlock_wrlock(&g_introspect_lock);
   333→    free(g_introspect.body);
   334→    g_introspect.body = NULL;
   335→    g_introspect.len  = 0;
   336→    pthread_rwlock_unlock(&g_introspect_lock);
   337→}

