    40→/* ------------------------------------------------------------------------- */
    41→
    42→/* Extracts an integer value from a cJSON object and asserts its presence. */
    43→static int
    44→json_get_int(const cJSON *parent, const char *key)
    45→{
    46→    const cJSON *item = cJSON_GetObjectItemCaseSensitive(parent, key);
    47→    assert_non_null(item);
    48→    assert_true(cJSON_IsNumber(item));
    49→    return item->valueint;
    50→}
    51→
    52→/* Returns the number of occurrences of `needle` inside `haystack`. */
    53→static size_t
    54→substr_count(const char *haystack, const char *needle)
    55→{
    56→    size_t count = 0;
    57→    const char *pos = haystack;
    58→
    59→    while ((pos = strstr(pos, needle)) != NULL) {
    60→        ++count;
    61→        pos += strlen(needle);
    62→    }
    63→    return count;
    64→}
