    69→
    70→static void
    71→test_generate_texture_success(void **state)
    72→{
    73→    (void)state; /* Unused */
    74→
    75→    /* GIVEN a valid procedural pattern */
    76→    const char *pattern     = "PerlinNoise";
    77→    const uint32_t seed     = 42;
    78→    const char *palette_id  = "retro-neon";
    79→
    80→    char *error = NULL;
    81→
    82→    /* WHEN generating a texture */
    83→    texture_t *tex = texture_service_generate_texture(pattern, seed, palette_id, &error);
    84→
    85→    /* THEN a non-NULL handle is returned and no error is set */
