   178→/* ------------------------------------------------------------------------- */
   179→
   180→typedef struct {
   181→    const char *pattern;
   182→    texture_t *out_texture;
   183→    char *out_error;
   184→} worker_ctx_t;
   185→
   186→static void *
   187→worker_generate(void *arg)
   188→{
   189→    worker_ctx_t *ctx = arg;
   190→    ctx->out_texture = texture_service_generate_texture(ctx->pattern,
   191→                                                        (uint32_t)pthread_self(),
   192→                                                        "mono-ink",
   193→                                                        &ctx->out_error);
   194→    return NULL;
   195→}
