   197→#define THREAD_COUNT 8
   198→
   199→static void
   200→test_thread_safety(void **state)
   201→{
   202→    (void)state;
   203→
   204→    pthread_t threads[THREAD_COUNT];
   205→    worker_ctx_t contexts[THREAD_COUNT] = {0};
   206→
   207→    /* Spawn multiple generators in parallel */
   208→    for (size_t i = 0; i < THREAD_COUNT; ++i) {
   209→        contexts[i].pattern = (i % 2 == 0) ? "PerlinNoise" : "Voronoi";
   210→        assert_int_equal(0, pthread_create(&threads[i], NULL, worker_generate, &contexts[i]));
   211→    }
   212→
   213→    /* Wait for all threads and evaluate results */
   214→    for (size_t i = 0; i < THREAD_COUNT; ++i) {
   215→        pthread_join(threads[i], NULL);
