   217→        assert_non_null(contexts[i].out_texture);
   218→        assert_null(contexts[i].out_error);
   219→
   220→        /* Basic sanity: unique IDs */
   221→        for (size_t j = 0; j < i; ++j) {
   222→            assert_string_not_equal(contexts[i].out_texture->id,
   223→                                    contexts[j].out_texture->id);
   224→        }
   225→    }
   226→
   227→    /* Clean-up */
   228→    for (size_t i = 0; i < THREAD_COUNT; ++i) {
   229→        texture_service_free_texture(contexts[i].out_texture);
   230→    }
   231→}
