    45→/*
    46→ * Convert a Palette domain object into a cJSON representation.
    47→ */
    48→static cJSON *palette_to_json(const Palette *palette)
    49→{
    50→    assert(palette != NULL);
    51→
    52→    cJSON *json = cJSON_CreateObject();
    53→    if (!json)
    54→        return NULL;
    55→
    56→    cJSON_AddStringToObject(json, "id", palette->id);
    57→    cJSON_AddStringToObject(json, "name", palette->name);
    58→
    59→    cJSON *colors = cJSON_AddArrayToObject(json, "colors");
    60→    for (size_t i = 0; i < palette->color_count; ++i)
    61→    {
    62→        cJSON_AddItemToArray(colors, cJSON_CreateString(palette->colors[i]));
    63→    }
    64→
    65→    cJSON_AddStringToObject(json, "createdAt", palette->created_at_iso8601);
    66→    cJSON_AddStringToObject(json, "updatedAt", palette->updated_at_iso8601);
    67→
    68→    return json;
    69→}
