    71→/*
    72→ * Parse query parameters ?page=<n>&size=<m>.  Defaults are taken from
    73→ * configuration if params are missing.  Returns 0 on success, -1 on failure.
    74→ */
    75→static int parse_pagination(const HttpRequest *req,
    76→                            Pagination       *out_pg,
    77→                            char            **error_msg)
    78→{
    79→    assert(req != NULL);
    80→    assert(out_pg != NULL);
    81→
    82→    const char *page_str = http_request_query_param(req, "page");
    83→    const char *size_str = http_request_query_param(req, "size");
    84→
    85→    uint32_t page = page_str ? (uint32_t)strtoul(page_str, NULL, 10)
    86→                             : CONFIG_DEFAULT_PAGE;
    87→    uint32_t size = size_str ? (uint32_t)strtoul(size_str, NULL, 10)
    88→                             : CONFIG_DEFAULT_PAGE_SIZE;
    89→
    90→    if (page == 0)
    91→        page = CONFIG_DEFAULT_PAGE; /* page numbers start at 1 */
    92→
    93→    if (size == 0 || size > CONFIG_MAX_PAGE_SIZE)
    94→    {
    95→        asprintf(error_msg,
    96→                 "Page size must be between 1 and %u",
    97→                 CONFIG_MAX_PAGE_SIZE);
    98→        return -1;
    99→    }
   100→
   101→    out_pg->page = page;
   102→    out_pg->size = size;
   103→    return 0;
   104→}
