   106→/*
   107→ * Push JSON to HttpResponse and handle memory.
   108→ */
   109→static int json_to_response(HttpResponse *resp, cJSON *json, int status_code)
   110→{
   111→    char *payload = cJSON_PrintUnformatted(json);
   112→    if (!payload)
   113→        return -1;
   114→
   115→    http_response_set_status(resp, status_code);
   116→    http_response_set_header(resp, "Content-Type", "application/json");
   117→    http_response_set_body(resp, payload, strlen(payload));
   118→
   119→    free(payload);
   120→    return 0;
   121→}
