   177→void palette_handler_handle_get_list(PaletteHandler    *handler,
   178→                                     const HttpRequest *req,
   179→                                     HttpResponse      *resp)
   180→{
   181→    Pagination pg = {0};
   182→    char *pg_err  = NULL;
   183→
   184→    if (parse_pagination(req, &pg, &pg_err) < 0)
