   193→    RepositoryResult *repo_res = palette_repository_fetch_page(
   194→        handler->repo, pg.page, pg.size);
   195→
   196→    if (repo_res->error)
   197→    {
   198→        logger_error(handler->log, "repository",
   199→                     "Failed to fetch palettes: %s", repo_res->error);
