   259→void palette_handler_handle_create(PaletteHandler    *handler,
   260→                                   const HttpRequest *req,
   261→                                   HttpResponse      *resp)
   262→{
   263→    const char *body      = http_request_body(req);
   264→    size_t      body_len  = http_request_body_length(req);
   265→    char       *val_error = NULL;
   266→
   267→    /* Basic JSON schema validation */
   268→    if (!validation_validate_json(body, body_len,
   269→                                  "schemas/palette_create.json",
   270→                                  &val_error))
   271→    {
   272→        http_response_send_error(resp, HTTP_STATUS_BAD_REQUEST, val_error);
   273→        free(val_error);
   274→        return;
   275→    }
   276→
   277→    cJSON *json = cJSON_ParseWithLength(body, body_len);
   278→    if (!json)
   279→    {
   280→        http_response_send_error(resp, HTTP_STATUS_BAD_REQUEST,
   281→                                 "Malformed JSON");
   282→        return;
   283→    }
   284→
   285→    const char *name = cJSON_GetStringValue(cJSON_GetObjectItem(json, "name"));
   286→    cJSON      *col  = cJSON_GetObjectItem(json, "colors");
   287→
   288→    size_t color_count = (size_t)cJSON_GetArraySize(col);
   289→    char  **colors     = calloc(color_count, sizeof(char *));
   290→    if (!colors)
   291→    {
   292→        cJSON_Delete(json);
   293→        http_response_send_error(resp, HTTP_STATUS_INTERNAL_SERVER_ERROR,
   294→                                 "Memory allocation failed");
   295→        return;
   296→    }
   297→
   298→    for (size_t i = 0; i < color_count; ++i)
   299→    {
   300→        const char *cstr = cJSON_GetStringValue(
   301→            cJSON_GetArrayItem(col, (int)i));
   302→        colors[i] = strdup(cstr);
   303→    }
   304→
   305→    PaletteCreateSpec spec = {
   306→        .name        = name,
   307→        .colors      = colors,
   308→        .color_count = color_count,
   309→    };
   310→
   311→    Palette *created = palette_repository_create(handler->repo, &spec);
   312→    palette_create_spec_free(&spec); /* frees colors list */
   313→
   314→    if (!created)
   315→    {
   316→        cJSON_Delete(json);
   317→        http_response_send_error(resp, HTTP_STATUS_CONFLICT,
   318→                                 "Palette with the same name already exists");
   319→        return;
   320→    }
   321→
   322→    cJSON *resp_json = palette_to_json(created);
   323→    json_to_response(resp, resp_json, HTTP_STATUS_CREATED);
   324→
   325→    cJSON_Delete(resp_json);
   326→    cJSON_Delete(json);
   327→    palette_free(created);
   328→
   329→    metrics_inc_counter(handler->metrics,
   330→                        "palette_create_requests_total", 1);
   331→}
