    54→/* Guard state for thread-safe handler */
    55→typedef struct
    56→{
    57→    TextureRepository *repo;       /* Injected storage adapter (non-null) */
    58→    MetricsCollector  *metrics;    /* Global metrics sink (may be null)   */
    59→    pthread_rwlock_t   lock;       /* Protects repository multi-step ops  */
    60→    bool               ready;      /* Handler has been initialized        */
    61→} TextureHandlerState;
    62→
