   127→/**
   128→ * Create a new texture based on the DTO provided by higher layers. This
   129→ * function validates all fields, generates an ID, persists the record, and
   130→ * returns a deep-copied Texture object that the caller must free.
   131→ */
   132→Texture *texture_handler_create(TextureHandler *handler,
   133→                                const TextureInput *input,
   134→                                TextureError *err)
   135→{
   136→    TextureHandlerState *state = (TextureHandlerState *)handler;
   137→    if (!state || !state->ready)
   138→    {
   139→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   140→        return NULL;
   141→    }
   142→
   143→    /* Validate input first */
   144→    if (!_validate_texture_input(input, err))
   145→        return NULL;
   146→
   147→    /* Build Texture domain object */
   148→    Texture tx      = {0};
   149→    tx.id           = _generate_uuid();
   150→    tx.name         = strndup(input->name, MAX_TEXTURE_NAME_LEN);
   151→    tx.color_profile= strndup(input->color_profile, MAX_COLOR_PROFILE_LEN);
   152→    tx.width        = input->width;
   153→    tx.height       = input->height;
   154→    tx.created_at   = (uint64_t)time(NULL);
   155→
   156→    if (!tx.id || !tx.name || !tx.color_profile)
   157→    {
   158→        _set_error(err, TX_ERR_OOM, "Failed to allocate texture attributes");
   159→        goto cleanup_fail;
   160→    }
   161→
   162→    /* Serialize metadata payload */
   163→    tx.metadata = _texture_to_json(&tx, err);
   164→    if (!tx.metadata)
   165→        goto cleanup_fail;
   166→
   167→    /* Acquire write-lock for repository update */
   168→    if (pthread_rwlock_wrlock(&state->lock) != 0)
   169→    {
   170→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire write lock");
   171→        goto cleanup_fail;
   172→    }
   173→
   174→    bool persist_ok = repository_save_texture(state->repo, &tx, err);
   175→    pthread_rwlock_unlock(&state->lock);
   176→
   177→    if (!persist_ok)
   178→        goto cleanup_fail;
   179→
   180→    /* Metrics */
   181→    if (state->metrics)
   182→        metrics_counter_inc(state->metrics, "texture_created_total", 1);
   183→
   184→    /* Deep copy result for caller (repository may own original memory) */
   185→    Texture *result = texture_clone(&tx, err);
   186→    texture_free(&tx); /* Free local copy */
   187→
   188→    log_info("[texture-handler] Created texture '%s' (%ux%u)", result->id, result->width, result->height);
   189→    return result;
   190→
   191→cleanup_fail:
   192→    texture_free(&tx);
   193→    return NULL;
   194→}
