   196→/**
   197→ * Retrieve a single texture by its UUID. Caller is responsible for freeing
   198→ * the returned object via texture_free().
   199→ */
   200→Texture *texture_handler_get(TextureHandler *handler, const char *texture_id, TextureError *err)
   201→{
   202→    TextureHandlerState *state = (TextureHandlerState *)handler;
   203→    if (!state || !state->ready)
   204→    {
   205→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   206→        return NULL;
   207→    }
   208→
   209→    if (!validation_is_uuid(texture_id))
   210→    {
   211→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "Invalid UUID provided: '%s'", texture_id);
   212→        return NULL;
   213→    }
   214→
   215→    if (pthread_rwlock_rdlock(&state->lock) != 0)
   216→    {
   217→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire read lock");
   218→        return NULL;
   219→    }
   220→
   221→    Texture *tx = repository_get_texture(state->repo, texture_id, err);
   222→    pthread_rwlock_unlock(&state->lock);
   223→
   224→    if (!tx)
   225→        return NULL; /* Error already populated */
   226→
   227→    if (state->metrics)
   228→        metrics_counter_inc(state->metrics, "texture_fetched_total", 1);
   229→
   230→    return tx; /* Ownership transferred to caller */
   231→}
