   280→/**
   281→ * Deletes a texture by ID.  Returns true on success, false otherwise.
   282→ */
   283→bool texture_handler_delete(TextureHandler *handler, const char *texture_id, TextureError *err)
   284→{
   285→    TextureHandlerState *state = (TextureHandlerState *)handler;
   286→    if (!state || !state->ready)
   287→    {
   288→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   289→        return false;
   290→    }
   291→
   292→    if (!validation_is_uuid(texture_id))
   293→    {
   294→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "Invalid UUID '%s'", texture_id);
   295→        return false;
   296→    }
   297→
   298→    if (pthread_rwlock_wrlock(&state->lock) != 0)
   299→    {
   300→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire write lock");
   301→        return false;
   302→    }
   303→
   304→    bool ok = repository_delete_texture(state->repo, texture_id, err);
   305→    pthread_rwlock_unlock(&state->lock);
   306→
   307→    if (ok && state->metrics)
   308→        metrics_counter_inc(state->metrics, "texture_deleted_total", 1);
   309→
   310→    log_info("[texture-handler] Deleted texture '%s' (%s)", texture_id, ok ? "ok" : "not-found");
   311→    return ok;
   312→}
