   317→
   318→static void _set_error(TextureError *out, TextureErrorCode code, const char *fmt, ...)
   319→{
   320→    if (!out)
   321→        return;
   322→
   323→    va_list ap;
   324→    va_start(ap, fmt);
   325→    vsnprintf(out->message, sizeof(out->message), fmt, ap);
   326→    va_end(ap);
   327→
   328→    out->code = code;
   329→}
