   331→static bool _validate_texture_input(const TextureInput *in, TextureError *err)
   332→{
   333→    if (!in)
   334→    {
   335→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "TextureInput cannot be NULL");
   336→        return false;
   337→    }
   338→
   339→    if (!validation_is_valid_name(in->name, MAX_TEXTURE_NAME_LEN))
   340→    {
   341→        _set_error(err, TX_ERR_VALIDATION, "Invalid texture name");
   342→        return false;
   343→    }
   344→
