### File 5: Updated `palette_service.c` (Key Changes)

```c
#include "sc_errors.h"

/* Service-level functions now return sc_unified_error_t* */
sc_unified_error_t*
palette_service_get_palette_by_id(const char *id, palette_record_t *out_record)
{
    if (!g_ctx.initialized) {
        return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_INTERNAL, 500,
                               "Service not initialized");
    }

    if (!id || !out_record) {
        g_ctx.metrics.read_err++;
        return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_INVALID_ARGUMENT, 400,
                               "Invalid arguments: id and out_record must not be NULL");
    }

    pthread_rwlock_rdlock(&g_ctx.lock);
    palette_record_t *rec = NULL;
    HASH_FIND_STR(g_ctx.records, id, rec);
    pthread_rwlock_unlock(&g_ctx.lock);

    if (!rec) {
        g_ctx.metrics.read_err++;
        return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_NOT_FOUND, 404,
                               "Palette with id=%s not found", id);
    }

    memcpy(out_record, rec, sizeof(*out_record));
    g_ctx.metrics.read_ok++;
    return NULL;  /* Success */
}

sc_unified_error_t*
palette_service_delete_palette(const char *id)
{
    if (!g_ctx.initialized) {
        return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_INTERNAL, 500,
                               "Service not initialized");
    }

    if (!id) {
        g_ctx.metrics.delete_err++;
        return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_INVALID_ARGUMENT, 400,
                               "Palette id cannot be NULL");
    }

    pthread_rwlock_wrlock(&g_ctx.lock);
    palette_record_t *rec = NULL;
    HASH_FIND_STR(g_ctx.records, id, rec);
    if (rec) {
        HASH_DEL(g_ctx.records, rec);
        free(rec);
        pthread_rwlock_unlock(&g_ctx.lock);

        g_ctx.metrics.delete_ok++;
        LOGI("Deleted palette id=%s", id);
        return NULL;  /* Success */
    }
    pthread_rwlock_unlock(&g_ctx.lock);

    g_ctx.metrics.delete_err++;
    return sc_error_create(SC_DOMAIN_PALETTE, PAL_ERR_NOT_FOUND, 404,
                           "Palette with id=%s not found for deletion", id);
}
