#include "sc_errors.h"

/* Updated to accept unified error objects */
RestResponse
rest_fallback_from_service_error(const RestRequest *req,
                                 const sc_unified_error_t *err)
{
    if (err == NULL) {
        /* No error - this shouldn't happen but handle gracefully */
        return rest_fallback_not_found(req);
    }

    LOG_WARN("[REST] Service error from domain '%s': %s (code=%d, http=%d)",
             sc_domain_str(err->domain),
             err->message ? err->message : "no message",
             err->code,
             err->http_status_code);

    char *payload = build_error_payload(
        err->http_status_code,
        sc_domain_str(err->domain),
        "%s", err->message ? err->message : "An error occurred");

    RestResponse res = {
        .status_code  = err->http_status_code,
        .content_type = MIME_APP_JSON,
        .body         = payload,
        .body_len     = strlen(payload),
        .must_free    = true
    };

    return res;
}
